bool InitializeImu() {
    imu_get_dev_info();
    return imu_type != DEV_NO_FIND;
}

ImuBridgeSample ReadImuSample() {
    ImuBridgeSample sample{};

    imu_get_dev_info();
    sample.imu_type = imu_type;
    if (imu_type == DEV_NO_FIND) {
        return sample;
    }

    switch (imu_type) {
        case DEV_IMU660RA:
            imu660ra_get_acc();
            imu660ra_get_gyro();
            sample.acc_x = imu660ra_acc_x;
            sample.acc_y = imu660ra_acc_y;
            sample.acc_z = imu660ra_acc_z;
            sample.gyro_x = imu660ra_gyro_x;
            sample.gyro_y = imu660ra_gyro_y;
            sample.gyro_z = imu660ra_gyro_z;
            break;
        case DEV_IMU660RB:
            imu660rb_get_acc();
            imu660rb_get_gyro();
            sample.acc_x = imu660rb_acc_x;
            sample.acc_y = imu660rb_acc_y;
            sample.acc_z = imu660rb_acc_z;
            sample.gyro_x = imu660rb_gyro_x;
            sample.gyro_y = imu660rb_gyro_y;
            sample.gyro_z = imu660rb_gyro_z;
            break;
        case DEV_IMU963RA:
            imu963ra_get_acc();
            imu963ra_get_gyro();
            imu963ra_get_mag();
            sample.acc_x = imu963ra_acc_x;
            sample.acc_y = imu963ra_acc_y;
            sample.acc_z = imu963ra_acc_z;
            sample.gyro_x = imu963ra_gyro_x;
            sample.gyro_y = imu963ra_gyro_y;
            sample.gyro_z = imu963ra_gyro_z;
            sample.mag_x = imu963ra_mag_x;
            sample.mag_y = imu963ra_mag_y;
            sample.mag_z = imu963ra_mag_z;
            break;
        default:
            return sample;
    }

    sample.valid = true;
    return sample;
}

