namespace {

void ApplyOne(const char* pwm_path, const char* gpio_path, int signed_duty) {
    const int clamped = std::clamp(signed_duty, -9000, 9000);
    if (clamped >= 0) {
        gpio_set_level(gpio_path, 1);
        pwm_set_duty(pwm_path, static_cast<uint16_t>(clamped));
    } else {
        gpio_set_level(gpio_path, 0);
        pwm_set_duty(pwm_path, static_cast<uint16_t>(std::abs(clamped)));
    }
}

}  // namespace

bool InitializeMotor() {
    return true;
}

void ApplyMotorCommand(int left_pwm, int right_pwm) {
    ApplyOne(kLeftMotorPwmPath, kLeftMotorGpioPath, left_pwm);
    ApplyOne(kRightMotorPwmPath, kRightMotorGpioPath, right_pwm);
}

void DisableMotorOutput() {
    pwm_set_duty(kLeftMotorPwmPath, 0);
    pwm_set_duty(kRightMotorPwmPath, 0);
}

