class ImuAdapter final : public port::IImuAdapter {
public:
    bool Initialize(const port::HardwareProfile& profile, port::DiagnosticSink& diagnostics) override {
        if (!port::IsEnabled(profile.imu)) {
            diagnostics.Emit({port::DiagnosticLevel::kInfo,
                              "imu.disabled",
                              "imu subsystem disabled by hardware profile",
                              port::NowMs()});
            enabled_ = false;
            ready_ = false;
            return true;
        }

        enabled_ = true;
        adaptation_hook_ = profile.imu.mode == port::SubsystemMode::kAdaptationHook;
        hook_name_ = profile.imu.hook;

        if (adaptation_hook_) {
            ready_ = true;
            diagnostics.Emit({port::DiagnosticLevel::kWarning,
                              "imu.init.hook",
                              "imu direct path bypassed; adaptation hook selected: " + hook_name_,
                              port::NowMs()});
            return true;
        }

        ready_ = true_ls2k0300::InitializeImu();
        diagnostics.Emit({ready_ ? port::DiagnosticLevel::kInfo : port::DiagnosticLevel::kFailSafe,
                          "imu.init",
                          ready_ ? "imu initialized through true_ls2k0300 bridge" : "imu unavailable",
                          port::NowMs()});
        if (ready_) {
            const true_ls2k0300::ImuBridgeSample sample = true_ls2k0300::ReadImuSample();
            diagnostics.Emit({sample.valid ? port::DiagnosticLevel::kInfo : port::DiagnosticLevel::kWarning,
                              "imu.detect",
                              std::string("imu detection path selected: ") + ImuTypeName(sample.imu_type),
                              port::NowMs()});
        }
        return ready_;
    }

    port::ImuSample Read(port::DiagnosticSink& diagnostics) override {
        port::ImuSample out{};
        out.capture_time_ms = port::NowMs();
        if (!enabled_ || !ready_) {
            return out;
        }

        if (adaptation_hook_) {
            out.valid = false;
            port::EmitRateLimited(diagnostics,
                                  {port::DiagnosticLevel::kWarning,
                                   "imu.hook.read",
                                   "imu adaptation hook selected with no concrete phase-1 implementation: " +
                                       hook_name_,
                                   out.capture_time_ms},
                                  1000);
            return out;
        }

        const true_ls2k0300::ImuBridgeSample sample = true_ls2k0300::ReadImuSample();
        if (!sample.valid) {
            return out;
        }

        out.valid = true;
        out.acc_x = static_cast<float>(sample.acc_x);
        out.acc_y = static_cast<float>(sample.acc_y);
        out.acc_z = static_cast<float>(sample.acc_z);
        out.gyro_x = static_cast<float>(sample.gyro_x);
        out.gyro_y = static_cast<float>(sample.gyro_y);
        out.gyro_z = static_cast<float>(sample.gyro_z);
        return out;
    }

    void Shutdown(port::DiagnosticSink& diagnostics) override {
        ready_ = false;
        diagnostics.Emit({port::DiagnosticLevel::kInfo,
                          "imu.shutdown",
                          "imu adapter shutdown complete",
                          port::NowMs()});
    }

    bool Ready() const override { return ready_; }

private:
    bool enabled_ = false;
    bool ready_ = false;
    bool adaptation_hook_ = false;
    std::string hook_name_ = "direct-match";
};

