class EncoderAdapter final : public port::IEncoderAdapter {
public:
    bool Initialize(const port::HardwareProfile& profile, port::DiagnosticSink& diagnostics) override {
        if (!port::IsEnabled(profile.encoder)) {
            diagnostics.Emit({port::DiagnosticLevel::kInfo,
                              "encoder.disabled",
                              "encoder subsystem disabled by hardware profile",
                              port::NowMs()});
            enabled_ = false;
            ready_ = false;
            return true;
        }

        enabled_ = true;
        adaptation_hook_ = profile.encoder.mode == port::SubsystemMode::kAdaptationHook;
        hook_name_ = profile.encoder.hook;

        if (adaptation_hook_) {
            ready_ = true;
            diagnostics.Emit({port::DiagnosticLevel::kWarning,
                              "encoder.init.hook",
                              "encoder direct path bypassed; adaptation hook selected: " + hook_name_,
                              port::NowMs()});
            return true;
        }

        have_baseline_ = false;
        ready_ = true;
        diagnostics.Emit({ready_ ? port::DiagnosticLevel::kInfo : port::DiagnosticLevel::kFailSafe,
                          "encoder.init",
                          ready_ ? "encoder initialized through true_ls2k0300 bridge" : "encoder backend unavailable",
                          port::NowMs()});
        return ready_;
    }

    port::EncoderDelta ReadDelta(port::DiagnosticSink& diagnostics) override {
        port::EncoderDelta out{};
        out.capture_time_ms = port::NowMs();
        if (!enabled_ || !ready_) {
            return out;
        }

        if (adaptation_hook_) {
            out.valid = false;
            port::EmitRateLimited(diagnostics,
                                  {port::DiagnosticLevel::kWarning,
                                   "encoder.hook.read",
                                   "encoder adaptation hook selected with no concrete phase-1 implementation: " +
                                       hook_name_,
                                   out.capture_time_ms},
                                  1000);
            return out;
        }

        const true_ls2k0300::EncoderCounts counts = true_ls2k0300::ReadEncoderCounts();
        if (!counts.valid) {
            return out;
        }

        if (!have_baseline_) {
            have_baseline_ = true;
            last_left_ = counts.left;
            last_right_ = counts.right;
            port::EmitRateLimited(diagnostics,
                                  {port::DiagnosticLevel::kWarning,
                                   "encoder.baseline",
                                   "encoder baseline established; first absolute sample is not emitted as a delta",
                                   out.capture_time_ms},
                                  1000);
            return out;
        }

        const int left_delta = counts.left - last_left_;
        const int right_delta = counts.right - last_right_;
        last_left_ = counts.left;
        last_right_ = counts.right;

        if (std::abs(left_delta) > 20000 || std::abs(right_delta) > 20000) {
            have_baseline_ = false;
            port::EmitRateLimited(diagnostics,
                                  {port::DiagnosticLevel::kWarning,
                                   "encoder.delta.jump",
                                   "encoder absolute-count jump exceeded plausibility threshold; baseline reset",
                                   out.capture_time_ms},
                                  1000);
            return out;
        }

        out.left = left_delta;
        out.right = right_delta;
        out.valid = true;
        return out;
    }

    void Shutdown(port::DiagnosticSink& diagnostics) override {
        ready_ = false;
        have_baseline_ = false;
        diagnostics.Emit({port::DiagnosticLevel::kInfo,
                          "encoder.shutdown",
                          "encoder adapter shutdown complete",
                          port::NowMs()});
    }

    bool Ready() const override { return ready_; }

private:
    bool enabled_ = false;
    bool ready_ = false;
    bool adaptation_hook_ = false;
    std::string hook_name_ = "direct-match";
    bool have_baseline_ = false;
    int last_left_ = 0;
    int last_right_ = 0;
};

}  // namespace

