bool TryParseInt(const char* text, int& out) {
    if (text == nullptr || text[0] == '\0') {
        return false;
    }
    try {
        out = std::stoi(text);
        return true;
    } catch (...) {
        return false;
    }
}

int ReadIntEnv(const char* key, int fallback) {
    int value = fallback;
    const char* text = std::getenv(key);
    if (TryParseInt(text, value)) {
        return value;
    }
    return fallback;
}

std::optional<bool> ReadBoolEnv(const char* key) {
    const char* raw = std::getenv(key);
    if (raw == nullptr) {
        return std::nullopt;
    }
    std::string token(raw);
    for (char& c : token) {
        c = static_cast<char>(std::tolower(static_cast<unsigned char>(c)));
    }
    if (token == "1" || token == "true" || token == "yes" || token == "on") {
        return true;
    }
    if (token == "0" || token == "false" || token == "no" || token == "off") {
        return false;
    }
    return std::nullopt;
}

bool ReadIntFromFile(const std::string& path, int& out) {
    std::ifstream input(path);
    if (!input.is_open()) {
        return false;
    }
    input >> out;
    return !input.fail();
}

class PowerMonitorAdapter final : public port::IPowerMonitorAdapter {
public:
    bool Initialize(port::DiagnosticSink& diagnostics) override {
        initialized_ = true;
        ready_ = true;
        diagnostics.Emit({port::DiagnosticLevel::kInfo,
                          "power.init",
                          "power monitor initialized with true_ls2k0300 adc bridge",
                          port::NowMs()});
        return true;
    }

    port::LowVoltageSample SampleLowVoltage(port::DiagnosticSink& diagnostics) override {
        port::LowVoltageSample sample{};
        sample.capture_time_ms = port::NowMs();
        sample.threshold = ReadIntEnv("LS2K_LOW_VOLTAGE_RAW_THRESHOLD", 400);

        if (const std::optional<bool> forced = ReadBoolEnv("LS2K_FORCE_LOW_VOLTAGE"); forced.has_value()) {
            sample.valid = true;
            sample.emergency = *forced;
            sample.source = "forced-env";
            port::EmitRateLimited(diagnostics,
                                  {*forced ? port::DiagnosticLevel::kFailSafe : port::DiagnosticLevel::kInfo,
                                   "startup.low_voltage.force",
                                   std::string("forced low-voltage emergency=") +
                                       (*forced ? "true" : "false"),
                                   sample.capture_time_ms},
                                  1000);
            return sample;
        }

        const char* override_path = std::getenv("LS2K_LOW_VOLTAGE_RAW_PATH");
        const char* adc_path =
            (override_path != nullptr && override_path[0] != '\0') ? override_path : true_ls2k0300::kBatteryAdcPath;
        if (!true_ls2k0300::ReadBatteryRaw(adc_path, sample.raw_value)) {
            if (override_path != nullptr && override_path[0] != '\0') {
                int raw = 0;
                if (ReadIntFromFile(override_path, raw)) {
                    sample.raw_value = raw;
                } else {
                    port::EmitRateLimited(diagnostics,
                                          {port::DiagnosticLevel::kWarning,
                                           "startup.low_voltage.path",
                                           "configured low-voltage raw path could not be read: " +
                                               std::string(override_path),
                                           sample.capture_time_ms},
                                          1000);
                }
            }
        }

        if (sample.raw_value >= 0) {
            sample.valid = true;
            sample.emergency = sample.raw_value <= sample.threshold;
            sample.source = adc_path;
            std::ostringstream message;
            message << "low-voltage raw check path=" << adc_path << " raw=" << sample.raw_value
                    << " threshold=" << sample.threshold;
            port::EmitRateLimited(diagnostics,
                                  {sample.emergency ? port::DiagnosticLevel::kFailSafe
                                                    : port::DiagnosticLevel::kInfo,
                                   "startup.low_voltage.raw",
                                   message.str(),
                                   sample.capture_time_ms},
                                  1000);
            return sample;
        }

        sample.valid = false;
        sample.emergency = true;
        sample.source = "unavailable";
        port::EmitRateLimited(diagnostics,
                              {port::DiagnosticLevel::kFailSafe,
                               "startup.low_voltage.unavailable",
                               "low-voltage backend unavailable; forcing fail-safe emergency veto",
                               sample.capture_time_ms},
                              1000);
        return sample;
    }

    bool Ready() const override { return initialized_ && ready_; }

private:
    bool initialized_ = false;
    bool ready_ = false;
};

